class Solution:
    def minSteps(self, n: int) -> int:
        if n == 1:
            return 0
        sum_steps = 0
        i = 2
        while i * i <= n:
            while n % i == 0:
                sum_steps += i
                n = n // i
            i += 1
        if n > 1:
            sum_steps += n
        return sum_steps

